css:
:root{--bg:#050509;--s1:#0c0c15;--s2:#131320;--brd:#222240;--brd2:#333358;--tx:#d0d0e6;--tx2:#8888aa;--tx3:#5e5e80;--w:#f2f2ff;--js:#f7df1e;--react:#61dafb;--ng:#dd0031;--green:#34d399;--red:#f87171;--yellow:#fbbf24;--purple:#a78bfa;--blue:#60a5fa;--pink:#f472b6;--code-bg:#08080f;--r:10px}
*{margin:0;padding:0;box-sizing:border-box}html{scroll-behavior:smooth}
body{font-family:'Manrope',sans-serif;background:var(--bg);color:var(--tx);line-height:1.7;font-size:14.5px;-webkit-font-smoothing:antialiased}
::-webkit-scrollbar{width:5px}::-webkit-scrollbar-track{background:var(--bg)}::-webkit-scrollbar-thumb{background:var(--purple);border-radius:9px}
.hero{padding:2.5rem 1.5rem 1.2rem;text-align:center;position:relative;overflow:hidden}
.hero::before{content:'';position:absolute;inset:0;background:radial-gradient(ellipse 80% 60% at 50% -10%,rgba(167,139,250,.1),transparent 60%);pointer-events:none}
.hero h1{font-family:'Literata',serif;font-size:clamp(1.8rem,5vw,3rem);font-weight:900;color:var(--w);letter-spacing:-.03em;line-height:1.15;position:relative}
.hero .sub{color:var(--tx2);margin-top:.5rem;font-size:.85rem}
.tabs{display:flex;justify-content:center;gap:.4rem;padding:.55rem .8rem;flex-wrap:wrap;border-bottom:1px solid var(--brd);position:sticky;top:0;z-index:1000;background:rgba(5,5,9,.92);backdrop-filter:blur(20px)}
.tab{font-family:'Manrope',sans-serif;font-size:.76rem;font-weight:700;padding:.45rem 1rem;border-radius:8px;border:1px solid var(--brd);background:var(--s1);color:var(--tx2);cursor:pointer;transition:.2s}
.tab:hover{border-color:var(--tx3);color:var(--tx)}.tab.active{color:var(--w);border-color:var(--purple);background:rgba(167,139,250,.1)}
.mn{max-width:880px;margin:0 auto;padding:1.5rem 1.25rem 5rem}
.tech{display:none;animation:fu .3s ease}.tech.active{display:block}
@keyframes fu{from{opacity:0;transform:translateY(10px)}to{opacity:1;transform:translateY(0)}}
.si{font-size:.88rem;color:var(--tx2);margin-bottom:1rem;padding-bottom:.8rem;border-bottom:1px solid var(--brd)}
.qa{background:var(--s1);border:1px solid var(--brd);border-radius:var(--r);margin-bottom:.4rem;overflow:hidden}
.qh{padding:.7rem .9rem;cursor:pointer;display:flex;align-items:flex-start;gap:.55rem;user-select:none;transition:background .2s}
.qh:hover{background:var(--s2)}
.lv{font-family:'JetBrains Mono',monospace;font-size:.5rem;font-weight:600;padding:.1rem .4rem;border-radius:20px;text-transform:uppercase;letter-spacing:.04em;flex-shrink:0;margin-top:.15rem}
.lv.b{background:rgba(52,211,153,.1);color:var(--green)}.lv.i{background:rgba(251,191,36,.1);color:var(--yellow)}.lv.a{background:rgba(248,113,113,.1);color:var(--red)}
.qt{font-weight:600;font-size:.8rem;color:var(--w);flex:1}
.tg{color:var(--tx3);font-size:.95rem;flex-shrink:0;transition:transform .3s}
.qa.open .tg{transform:rotate(45deg)}
.qb{max-height:0;overflow:hidden;transition:max-height .5s ease}
.qa.open .qb{max-height:15000px}
.qi{padding:0 .9rem .9rem}.qi p{margin-bottom:.3rem}
.fb{display:flex;gap:.3rem;margin-bottom:.6rem;flex-wrap:wrap}
.ft{background:var(--s1);border:1px solid var(--brd);color:var(--tx3);font-family:'Manrope',sans-serif;font-size:.68rem;font-weight:500;padding:.3rem .65rem;border-radius:20px;cursor:pointer;transition:.2s}
.ft:hover{border-color:var(--tx3)}.ft.active{background:var(--purple);border-color:var(--purple);color:#fff}
.ct{font-size:.72rem;color:var(--tx3);margin-bottom:.5rem}.ct b{color:var(--purple)}
/* Angular Q&A classes from existing file */
.qa-h,.qa-header{padding:.7rem .9rem;cursor:pointer;display:flex;align-items:flex-start;gap:.55rem;user-select:none;transition:background .2s}
.qa-h:hover{background:var(--s2)}
.qa-a,.qa-answer{max-height:0;overflow:hidden;transition:max-height .5s ease}
.qa.open .qa-a,.qa.open .qa-answer{max-height:15000px}
.qa-ai,.qa-answer-inner{padding:0 .9rem .9rem}.qa-ai p,.qa-answer-inner p{margin-bottom:.3rem}
.qa-question,.qq{font-weight:600;font-size:.8rem;color:var(--w);flex:1}
.qa-toggle{color:var(--tx3);font-size:.95rem;flex-shrink:0;transition:transform .3s}
.qa.open .qa-toggle{transform:rotate(45deg)}
.qa-level{font-family:'JetBrains Mono',monospace;font-size:.5rem;font-weight:600;padding:.1rem .4rem;border-radius:20px;text-transform:uppercase;letter-spacing:.04em;flex-shrink:0;margin-top:.15rem}
.qa-level.beginner,.lvl.b{background:rgba(52,211,153,.1);color:var(--green)}
.qa-level.intermediate,.lvl.i{background:rgba(251,191,36,.1);color:var(--yellow)}
.qa-level.advanced,.lvl.a{background:rgba(248,113,113,.1);color:var(--red)}
.lvl{font-family:'JetBrains Mono',monospace;font-size:.5rem;font-weight:600;padding:.1rem .4rem;border-radius:20px;text-transform:uppercase;letter-spacing:.04em;flex-shrink:0;margin-top:.15rem}
.fbtn,.filter-btn{background:var(--s1);border:1px solid var(--brd);color:var(--tx3);font-family:'Manrope',sans-serif;font-size:.68rem;font-weight:500;padding:.3rem .65rem;border-radius:20px;cursor:pointer;transition:.2s}
.fbtn:hover,.filter-btn:hover{border-color:var(--tx3)}.fbtn.active,.filter-btn.active{background:var(--purple);border-color:var(--purple);color:#fff}
.fbar,.filter-bar{display:flex;gap:.3rem;margin-bottom:.6rem;flex-wrap:wrap}
.counter{font-size:.72rem;color:var(--tx3);margin-bottom:.5rem}.counter b{color:var(--purple)}
.analogy,.an{background:rgba(167,139,250,.06);border-left:3px solid var(--purple);border-radius:0 8px 8px 0;padding:.7rem .85rem;margin:.4rem 0;font-size:.78rem}
.analogy::before,.an::before{content:'💡 Think of it this way';display:block;font-weight:700;font-size:.6rem;color:var(--purple);text-transform:uppercase;letter-spacing:.05em;margin-bottom:.2rem}
.tip,.tp{background:rgba(52,211,153,.06);border-left:3px solid var(--green);border-radius:0 8px 8px 0;padding:.7rem .85rem;margin:.4rem 0;font-size:.78rem}
.tip::before,.tp::before{content:'🔥 Pro Tip';display:block;font-weight:700;font-size:.6rem;color:var(--green);text-transform:uppercase;letter-spacing:.05em;margin-bottom:.2rem}
.warn,.wr{background:rgba(251,191,36,.06);border-left:3px solid var(--yellow);border-radius:0 8px 8px 0;padding:.7rem .85rem;margin:.4rem 0;font-size:.78rem}
.warn::before,.wr::before{content:'⚠️ Common Mistake';display:block;font-weight:700;font-size:.6rem;color:var(--yellow);text-transform:uppercase;letter-spacing:.05em;margin-bottom:.2rem}
.deep,.dp{background:rgba(96,165,250,.06);border-left:3px solid var(--blue);border-radius:0 8px 8px 0;padding:.7rem .85rem;margin:.4rem 0;font-size:.78rem}
.deep::before,.dp::before{content:'🔬 Under the Hood';display:block;font-weight:700;font-size:.6rem;color:var(--blue);text-transform:uppercase;letter-spacing:.05em;margin-bottom:.2rem}
pre{background:var(--code-bg);border:1px solid var(--brd);border-radius:8px;padding:.85rem;overflow-x:auto;margin:.4rem 0;font-size:.72rem;line-height:1.55;tab-size:2}
code{font-family:'JetBrains Mono',monospace;font-size:.72rem}
p code,li code{background:var(--s2);padding:.08em .3em;border-radius:4px;color:var(--pink);font-size:.72em}
ul,ol{padding-left:1.2rem;margin:.3rem 0}li{margin-bottom:.2rem}p{margin-bottom:.35rem}strong{color:var(--w)}
.tag{display:inline-block;font-size:.6rem;font-weight:600;padding:.1rem .4rem;border-radius:12px;margin-right:.2rem}.tag-r{background:rgba(221,0,49,.06);color:var(--ng)}.tag-g{background:rgba(52,211,153,.08);color:var(--green)}.tag-y{background:rgba(251,191,36,.08);color:var(--yellow)}.tag-p{background:rgba(167,139,250,.08);color:var(--purple)}.tag-b{background:rgba(96,165,250,.08);color:var(--blue)}
.card{background:var(--s1);border:1px solid var(--brd);border-radius:var(--r);padding:1.3rem;margin-bottom:.8rem}.card:hover{border-color:var(--brd2)}.card h2{font-family:'Literata',serif;font-size:1.15rem;font-weight:700;color:var(--w);margin-bottom:.5rem}.card h3{font-size:.88rem;font-weight:700;color:var(--green);margin:1rem 0 .4rem}.card h4{font-size:.8rem;font-weight:600;color:var(--purple);margin:.8rem 0 .3rem}
.grid2{display:grid;grid-template-columns:1fr 1fr;gap:.6rem;margin:.4rem 0}
.vis-count{color:var(--purple)}
.section{display:none;animation:fu .3s ease}.section.active{display:block}.section-intro{font-size:.88rem;color:var(--tx2);margin-bottom:1rem;padding-bottom:.8rem;border-bottom:1px solid var(--brd)}
.nav-btn,.snav,.sn{background:0;border:0;color:var(--tx3);font-family:'Manrope',sans-serif;font-size:.68rem;font-weight:500;padding:.5rem .7rem;cursor:pointer;border-bottom:2px solid transparent;transition:.2s;white-space:nowrap}.nav-btn:hover,.snav:hover,.sn:hover{color:var(--tx)}.nav-btn.active,.snav.active,.sn.active{color:var(--purple);border-bottom-color:var(--purple)}
.sub-nav{overflow-x:auto;white-space:nowrap;padding:.3rem .8rem;border-bottom:1px solid var(--brd)}.sub-nav-inner,.sni,.nav-inner{display:flex;gap:0;max-width:1300px;margin:0 auto}
.cd{background:var(--s1);border:1px solid var(--brd);border-radius:var(--r);padding:1.3rem;margin-bottom:.8rem}.cd:hover{border-color:var(--brd2)}.cd h2{font-family:'Literata',serif;font-size:1.15rem;font-weight:700;color:var(--w);margin-bottom:.5rem}.cd h3{font-size:.88rem;font-weight:700;color:var(--green);margin:1rem 0 .4rem}
.k,.kw{color:#c792ea}.s,.st{color:#c3e88d}.c,.cm{color:#546e7a}.f,.fn{color:#82aaff}.d,.dc{color:#ffcb6b}.n,.nu{color:#f78c6c}
.sc{display:none;animation:fu .3s ease}.sc.active{display:block}
@media(max-width:640px){.cd,.card{padding:1rem}pre{padding:.7rem;font-size:.66rem}.qh,.qa-h{padding:.6rem .75rem}.tab{padding:.35rem .7rem;font-size:.7rem}}
